/**
 * 获取请求的内容长度。
 * @return 请求的内容长度。
 * @since 1.3
 */
public long contentLength() {
    HttpURLConnection connection = null;
    try {
        connection = (HttpURLConnection) url.openConnection();
        connection.setRequestMethod("HEAD");
        connection.connect();
        return connection.getContentLengthLong();
    } catch (IOException e) {
        e.printStackTrace();
        // 返回-1表示获取失败
        return -1;
    } finally {
        if (connection != null) {
            connection.disconnect();
        }
    }
}

