/**
 * 计算一个恒等自同构（即图的自映射，其中每个顶点也映射到自身）。
 * @param graph 输入图
 * @param <V> 图的顶点类型
 * @param <E> 图的边类型
 * @return 从图到图的映射
 */
public static <V, E> IsomorphicGraphMapping<V, E> identity(Graph<V, E> graph) {
    // 创建一个恒等映射，即每个顶点映射到自身
    IsomorphicGraphMapping<V, E> mapping = new IsomorphicGraphMapping<V, E>() {

        @Override
        public V getVertexCorrespondence(V v, boolean forward) {
            // 顶点映射到自身
            return v;
        }

        @Override
        public E getEdgeCorrespondence(E e, boolean forward) {
            // 边映射到自身
            return e;
        }

        @Override
        public boolean hasVertexCorrespondence(V v) {
            // 检查顶点是否在图中
            return graph.containsVertex(v);
        }

        @Override
        public boolean hasEdgeCorrespondence(E e) {
            // 检查边是否在图中
            return graph.containsEdge(e);
        }
    };
    return mapping;
}

/**
 * 计算一个恒等自同构（即图的自映射，其中每个顶点也映射到自身）。
 * @param graph 输入图
 * @param <V> 图的顶点类型
 * @param <E> 图的边类型
 * @return 从图到图的映射
 */
public static <V, E> IsomorphicGraphMapping<V, E> identity(Graph<V, E> graph) {
    Map<V, V> vertexMap = new HashMap<>();
    Map<E, E> edgeMap = new HashMap<>();
    // 创建顶点映射
    for (V vertex : graph.vertexSet()) {
        vertexMap.put(vertex, vertex);
    }
    // 创建边映射
    for (E edge : graph.edgeSet()) {
        edgeMap.put(edge, edge);
    }
    return new IsomorphicGraphMapping<>(vertexMap, edgeMap, graph, graph);
}

