/**
 * 计算一个恒等自同构（即图的自映射，其中每个顶点也映射到自身）。
 * @param graph 输入图
 * @param <V> 图的顶点类型
 * @param <E> 图的边类型
 * @return 从图到图的映射
 */
public static <V, E> IsomorphicGraphMapping<V, E> identity(Graph<V, E> graph) {
    IsomorphicGraphMapping<V, E> mapping = new IsomorphicGraphMapping<>(graph, graph);
    for (V vertex : graph.vertexSet()) {
        mapping.addVertexMapping(vertex, vertex);
    }
    for (E edge : graph.edgeSet()) {
        V source = graph.getEdgeSource(edge);
        V target = graph.getEdgeTarget(edge);
        mapping.addEdgeMapping(edge, edge, source, target);
    }
    return mapping;
}

/**
 * 安排在JVM退出时删除指定文件。如果文件是目录，则删除该目录及所有子目录。
 * @param file 要删除的文件或目录，不能为空 {@code null}
 * @throws NullPointerException 如果文件为 {@code null}
 * @throws IOException 如果删除不成功
 */
public static void forceDeleteOnExit(File file) throws IOException {
    if (file == null) {
        throw new NullPointerException("File must not be null");
    }
    file.deleteOnExit();
    if (file.isDirectory()) {
        File[] files = file.listFiles();
        if (files != null) {
            for (File subFile : files) {
                forceDeleteOnExit(subFile);
            }
        }
    }
}

