/**
 * 构建一个完整的二分图
 * @param target 目标图对象
 * @param resultMap 用于存储生成的顶点
 */
public void generateGraph(Graph<V, E> target, Map<String, V> resultMap) {
    // 假设我们有两组顶点，分别命名为 "A" 和 "B"
    List<V> groupA = new ArrayList<>();
    List<V> groupB = new ArrayList<>();
    // 创建顶点并添加到对应的组中
    for (int i = 0; i < 5; i++) {
        V vertexA = target.addVertex();
        groupA.add(vertexA);
        resultMap.put("A" + i, vertexA);
        V vertexB = target.addVertex();
        groupB.add(vertexB);
        resultMap.put("B" + i, vertexB);
    }
    // 在两组顶点之间创建边
    for (V a : groupA) {
        for (V b : groupB) {
            target.addEdge(a, b);
        }
    }
}

/**
 * 构建一个完整的二分图
 * @param target 目标图对象
 * @param resultMap 用于存储生成的顶点
 */
public void generateGraph(Graph<V, E> target, Map<String, V> resultMap) {
    // 假设图有两个部分，分别称为左部和右部
    List<V> leftPart = new ArrayList<>();
    List<V> rightPart = new ArrayList<>();
    // 创建左部顶点
    for (int i = 0; i < 5; i++) {
        // 假设左部有5个顶点
        V vertex = target.addVertex();
        leftPart.add(vertex);
        resultMap.put("left_" + i, vertex);
    }
    // 创建右部顶点
    for (int i = 0; i < 5; i++) {
        // 假设右部有5个顶点
        V vertex = target.addVertex();
        rightPart.add(vertex);
        resultMap.put("right_" + i, vertex);
    }
    // 连接左部和右部的所有顶点
    for (V leftVertex : leftPart) {
        for (V rightVertex : rightPart) {
            target.addEdge(leftVertex, rightVertex);
        }
    }
}

