protected List<TimeRange> buildTimeRanges(long start, long end) {
    List<TimeRange> timeRanges = new ArrayList<>();
    while (start < end) {
        long nextEnd = Math.min(start + FETCH_DATA_DURATION, end);
        timeRanges.add(new TimeRange(start, nextEnd));
        start = nextEnd;
