/**
 * 将字符串中的 UTF-8 编码字节写入 {@link LinkedBuffer}。
 */
public static LinkedBuffer writeUTF8(final CharSequence str, final WriteSession session, final LinkedBuffer lb) {
    if (str == null) {
        return lb;
    }
    int length = str.length();
    int utf8Length = 0;
    // 计算 UTF-8 编码后的字节长度
    for (int i = 0; i < length; i++) {
        char c = str.charAt(i);
        if (c <= 0x7F) {
            utf8Length++;
        } else if (c <= 0x7FF) {
            utf8Length += 2;
        } else if (Character.isHighSurrogate(c)) {
            utf8Length += 4;
            // 跳过低代理项
            i++;
        } else {
            utf8Length += 3;
        }
    }
    // 确保 LinkedBuffer 有足够的空间
    if (lb.offset + utf8Length > lb.buffer.length) {
        lb = new LinkedBuffer(lb.buffer.length, lb);
    }
    // 写入 UTF-8 编码的字节
    for (int i = 0; i < length; i++) {
        char c = str.charAt(i);
        if (c <= 0x7F) {
            lb.buffer[lb.offset++] = (byte) c;
        } else if (c <= 0x7FF) {
            lb.buffer[lb.offset++] = (byte) (0xC0 | (c >> 6));
            lb.buffer[lb.offset++] = (byte) (0x80 | (c & 0x3F));
        } else if (Character.isHighSurrogate(c)) {
            int codePoint = Character.toCodePoint(c, str.charAt(i + 1));
            lb.buffer[lb.offset++] = (byte) (0xF0 | (codePoint >> 18));
            lb.buffer[lb.offset++] = (byte) (0x80 | ((codePoint >> 12) & 0x3F));
            lb.buffer[lb.offset++] = (byte) (0x80 | ((codePoint >> 6) & 0x3F));
            lb.buffer[lb.offset++] = (byte) (0x80 | (codePoint & 0x3F));
            // 跳过低代理项
            i++;
        } else {
            lb.buffer[lb.offset++] = (byte) (0xE0 | (c >> 12));
            lb.buffer[lb.offset++] = (byte) (0x80 | ((c >> 6) & 0x3F));
            lb.buffer[lb.offset++] = (byte) (0x80 | (c & 0x3F));
        }
    }
    return lb;
}

/**
 * 将字符串中的 UTF-8 编码字节写入 {@link LinkedBuffer}。
 */
public static LinkedBuffer writeUTF8(final CharSequence str, final WriteSession session, final LinkedBuffer lb) {
    if (str == null) {
        return lb;
    }
    int length = str.length();
    int utf8Length = 0;
    for (int i = 0; i < length; i++) {
        char c = str.charAt(i);
        if (c <= 0x7F) {
            utf8Length++;
        } else if (c <= 0x7FF) {
            utf8Length += 2;
        } else if (Character.isHighSurrogate(c)) {
            utf8Length += 4;
            // Skip the low surrogate
            i++;
        } else {
            utf8Length += 3;
        }
    }
    if (utf8Length > 65535) {
        throw new IllegalArgumentException("UTF-8 encoded string is too long: " + utf8Length);
    }
    LinkedBuffer buffer = lb;
    if (buffer == null) {
        buffer = LinkedBuffer.allocate();
    }
    Output output = session.getOutput();
    output.writeVarInt32(utf8Length, buffer);
    for (int i = 0; i < length; i++) {
        char c = str.charAt(i);
        if (c <= 0x7F) {
            buffer.buffer[buffer.offset++] = (byte) c;
        } else if (c <= 0x7FF) {
            buffer.buffer[buffer.offset++] = (byte) (0xC0 | (c >> 6));
            buffer.buffer[buffer.offset++] = (byte) (0x80 | (c & 0x3F));
        } else if (Character.isHighSurrogate(c)) {
            int codePoint = Character.toCodePoint(c, str.charAt(++i));
            buffer.buffer[buffer.offset++] = (byte) (0xF0 | (codePoint >> 18));
            buffer.buffer[buffer.offset++] = (byte) (0x80 | ((codePoint >> 12) & 0x3F));
            buffer.buffer[buffer.offset++] = (byte) (0x80 | ((codePoint >> 6) & 0x3F));
            buffer.buffer[buffer.offset++] = (byte) (0x80 | (codePoint & 0x3F));
        } else {
            buffer.buffer[buffer.offset++] = (byte) (0xE0 | (c >> 12));
            buffer.buffer[buffer.offset++] = (byte) (0x80 | ((c >> 6) & 0x3F));
            buffer.buffer[buffer.offset++] = (byte) (0x80 | (c & 0x3F));
        }
        if (buffer.offset == buffer.buffer.length) {
            buffer = buffer.next = LinkedBuffer.allocate();
        }
    }
    return buffer;
}

/**
 * 将字符串中的 UTF-8 编码字节写入 {@link LinkedBuffer}。
 *
 * @param str     要写入的字符串
 * @param session 写入会话
 * @param lb      目标 LinkedBuffer
 * @return 写入后的 LinkedBuffer
 */
public static LinkedBuffer writeUTF8(final CharSequence str, final WriteSession session, final LinkedBuffer lb) {
    if (str == null) {
        return lb;
    }
    int length = str.length();
    if (length == 0) {
        return lb;
    }
    LinkedBuffer buffer = lb;
    Output output = session.getOutput();
    for (int i = 0; i < length; i++) {
        char c = str.charAt(i);
        if (c <= 0x007F) {
            // 1 byte
            buffer = output.writeByte((byte) c, buffer);
        } else if (c <= 0x07FF) {
            // 2 bytes
            buffer = output.writeByte((byte) (0xC0 | (c >> 6)), buffer);
            buffer = output.writeByte((byte) (0x80 | (c & 0x3F)), buffer);
        } else {
            // 3 bytes
            buffer = output.writeByte((byte) (0xE0 | (c >> 12)), buffer);
            buffer = output.writeByte((byte) (0x80 | ((c >> 6) & 0x3F)), buffer);
            buffer = output.writeByte((byte) (0x80 | (c & 0x3F)), buffer);
        }
    }
    return buffer;
}

/**
 * 将字符串中的 UTF-8 编码字节写入 {@link LinkedBuffer}。
 */
public static LinkedBuffer writeUTF8(final CharSequence str, final WriteSession session, final LinkedBuffer lb) {
    if (str == null) {
        return lb;
    }
    int length = str.length();
    int utf8Length = 0;
    // 计算 UTF-8 编码后的字节长度
    for (int i = 0; i < length; i++) {
        char c = str.charAt(i);
        if (c <= 0x7F) {
            utf8Length++;
        } else if (c <= 0x7FF) {
            utf8Length += 2;
        } else if (Character.isHighSurrogate(c)) {
            utf8Length += 4;
            // 跳过低代理项
            i++;
        } else {
            utf8Length += 3;
        }
    }
    // 确保 LinkedBuffer 有足够的空间
    if (lb.offset + utf8Length > lb.buffer.length) {
        lb = LinkedBuffer.allocate(utf8Length, session.nextBufferSize(), lb);
    }
    // 将字符串编码为 UTF-8 并写入 LinkedBuffer
    for (int i = 0; i < length; i++) {
        char c = str.charAt(i);
        if (c <= 0x7F) {
            lb.buffer[lb.offset++] = (byte) c;
        } else if (c <= 0x7FF) {
            lb.buffer[lb.offset++] = (byte) (0xC0 | (c >> 6));
            lb.buffer[lb.offset++] = (byte) (0x80 | (c & 0x3F));
        } else if (Character.isHighSurrogate(c)) {
            char low = str.charAt(++i);
            int codePoint = Character.toCodePoint(c, low);
            lb.buffer[lb.offset++] = (byte) (0xF0 | (codePoint >> 18));
            lb.buffer[lb.offset++] = (byte) (0x80 | ((codePoint >> 12) & 0x3F));
            lb.buffer[lb.offset++] = (byte) (0x80 | ((codePoint >> 6) & 0x3F));
            lb.buffer[lb.offset++] = (byte) (0x80 | (codePoint & 0x3F));
        } else {
            lb.buffer[lb.offset++] = (byte) (0xE0 | (c >> 12));
            lb.buffer[lb.offset++] = (byte) (0x80 | ((c >> 6) & 0x3F));
            lb.buffer[lb.offset++] = (byte) (0x80 | (c & 0x3F));
        }
    }
    return lb;
}

/**
 * 将字符串中的 UTF-8 编码字节写入 {@link LinkedBuffer}。
 */
public static LinkedBuffer writeUTF8(final CharSequence str, final WriteSession session, final LinkedBuffer lb) {
    if (str == null) {
        return lb;
    }
    byte[] utf8Bytes = str.toString().getBytes(StandardCharsets.UTF_8);
    int length = utf8Bytes.length;
    // Ensure there is enough space in the buffer
    if (lb.offset + length > lb.buffer.length) {
        lb = LinkedBuffer.allocate(lb.nextBufferSize, lb);
    }
    // Write the length of the UTF-8 bytes
    session.writeVarInt32(length, lb);
    // Write the UTF-8 bytes
    System.arraycopy(utf8Bytes, 0, lb.buffer, lb.offset, length);
    lb.offset += length;
    return lb;
}

