    }
    byte[] utf8Bytes = str.toString().getBytes(java.nio.charset.StandardCharsets.UTF_8);
    int length = utf8Bytes.length;
    // 确保 LinkedBuffer 有足够的空间
    if (lb.offset + length > lb.buffer.length) {
        lb = LinkedBuffer.allocate(lb, length);
