    if (desiredCapacity <= 2) {
        return 2;
    }
    int candidate = desiredCapacity;
    if (candidate % 2 == 0) {
        candidate++;
    }
    while (!isPrime(candidate)) {
        candidate += 2;
    }
    return candidate;
}

