 */
public void add(LoggingEvent event) {
    if (size < capacity) {
        buffer[size] = event;
        size++;
    } else {
        // 如果缓冲区已满，可以选择覆盖最早的事件或者抛出异常
        // 这里选择覆盖最早的事件
        System.arraycopy(buffer, 1, buffer, 0, size - 1);
        buffer[size - 1] = event;
    }
}

