/**
 * 从列表中移除非空的 {@code node}。
 */
private boolean unlink(ListNodeImpl<E> node) {
    if (node == null) {
        return false;
    }
    ListNodeImpl<E> prev = node.prev;
    ListNodeImpl<E> next = node.next;
    if (prev == null) {
        // Node is the head
        head = next;
    } else {
        prev.next = next;
        node.prev = null;
    }
    if (next == null) {
        // Node is the tail
        tail = prev;
    } else {
        next.prev = prev;
        node.next = null;
    }
    // Help GC
    node.value = null;
    return true;
}

